private final class LexEngine {
    private let state: UnsafeMutableRawPointer
    private var replacement_buffer: [UInt16] = [UInt16](
        repeating: 0,
        count: Int(lex_replacement_buffer_length)
    )

    init() {
        let byte_count = Int(lex_state_size)
        let alignment = Int(lex_state_alignment)
        let state = UnsafeMutableRawPointer.allocate(
            byteCount: byte_count,
            alignment: alignment
        )
        lex_init(state)
        self.state = state
    }

    deinit {
        state.deallocate()
    }

    func reset() {
        lex_init(state)
    }

    func add(_ character: Character) {
        guard let ascii_code = Self.ascii_code(character) else {
            return
        }
        lex_add(state, ascii_code)
    }

    func backspace() {
        if !buffer_empty() {
            lex_backspace(state)
        }
    }

    func buffer_full() -> Bool {
        return lex_buffer_full(state)
    }

    func buffer_empty() -> Bool {
        return lex_buffer_empty(state)
    }

    func buffer_effective_full() -> Bool {
        return lex_buffer_effective_full(state)
    }

    func synthetic_backspaces() -> Int {
        return Int(lex_calculate_synthetic_backspaces(state))
    }

    func compose_replacement() -> String {
        var replacement_count: UInt8 = 0
        lex_compose_utf16_string_replacement(
            state,
            &replacement_buffer,
            &replacement_count
        )
        let count = Int(replacement_count)
        guard count > 0 else {
            return ""
        }
        return replacement_buffer.withUnsafeBufferPointer { buffer in
            return String(utf16CodeUnits: buffer.baseAddress!, count: count)
        }
    }

    private static func ascii_code(_ character: Character) -> UInt8? {
        var unicode_scalars = character.unicodeScalars.makeIterator()
        guard let unicode_scalar = unicode_scalars.next(), unicode_scalars.next() == nil else {
            return nil
        }
        guard unicode_scalar.isASCII else {
            return nil
        }
        return UInt8(unicode_scalar.value)
    }
}

private final class AppDelegate: NSObject, NSApplicationDelegate {
    fileprivate let engine = LexEngine()
    private var status_item: NSStatusItem?
